mapper.insert:
INSERT INTO user        /* 회원 테이블 */
(
    login_id            /* 로그인 ID */
  , password            /* 비밀번호 */
  , name                /* 닉네임 */
  , email               /* 이메일 */
  , role_code           /* 권한 코드 */
  , created_at          /* 등록 일시 */
)
VALUES
(
    #{loginId}
  , #{password}
  , #{name}
  , #{email}
  , #{roleCode}
  , NOW()
)

mapper.select:
SELECT password
  FROM user     /* 회원 테이블 */
 WHERE user_id = #{userId}

SELECT COUNT(*)
  FROM user         /* 회원 테이블 */
 WHERE email = #{email}
